const totalPaginas = 200;

return Array.from({ length: totalPaginas }, (_, i) => ({
  json: {
    pagina: i + 1
  }
}));

function parseDateBR(dataStr) {
  if (!dataStr) return null;
  const partes = String(dataStr).split('/');
  if (partes.length !== 3) return null;
  const [mes, dia, ano] = partes;
  return `${ano}-${String(mes).padStart(2, '0')}-${String(dia).padStart(2, '0')}`;
}

function toNumber(valor) {
  if (!valor) return 0;
  const n = Number(String(valor).replace(/\./g, '').replace(',', '.'));
  return isNaN(n) ? 0 : n;
}

function clean(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

let contratos = [];

if (Array.isArray($json?.data)) {
  contratos = $json.data.map(i => i?.data || i).filter(Boolean);
} else if (Array.isArray($json)) {
  contratos = $json.map(i => i?.data || i).filter(Boolean);
}

return contratos.map(contrato => {
  const loc = (contrato.inquilinos || [])[0] || {};
  const prop = (contrato.proprietarios_beneficiarios || [])[0] || {};

  return {
    json: {
      id_contrato: clean(contrato.id_contrato_con),
      identificador: clean(contrato.st_identificador_imo),
      endereco: clean(contrato.st_endereco_imo),
      numero: clean(contrato.st_numero_imo),
      complemento: clean(contrato.st_complemento_imo),
      bairro: clean(contrato.st_bairro_imo),
      cep: clean(contrato.st_cep_imo),
      inicio_contrato: parseDateBR(contrato.dt_inicio_con),
      fim_contrato: parseDateBR(contrato.dt_fim_con),
      valor_aluguel: toNumber(contrato.vl_aluguel_con),
      garantia_tipo: clean(contrato.fl_garantia_con),
      garantia_codigo: clean(contrato.fl_tipocaucaogarantia_con),
      garantia_descricao: clean(contrato.st_descricaogarantia_con),
      taxa_administracao: toNumber(contrato.tx_adm_con),
      dia_vencimento: clean(contrato.nm_diavencimento_con),
      mes_reajuste: clean(contrato.nm_mesreajuste_con),
      inicio_seguro: parseDateBR(contrato.dt_seguroincendioinicio_con),
      fim_seguro: parseDateBR(contrato.dt_seguroincendiofim_con),
      nome_locatario: clean(loc.st_fantasia_pes),
      telefone_locatario: clean(loc.st_celular_pes || loc.st_telefone_pes),
      email_locatario: clean(loc.st_email_pes),
      cpf_locatario: clean(loc.st_cnpj_pes),
      nome_proprietario: clean(prop.st_nome_pes),
      telefone_proprietario: clean(prop.st_celular_pes || prop.st_telefone_pes),
      email_proprietario: clean(prop.st_email_pes),
      cpf_proprietario: clean(prop.st_cnpj_pes)
    }
  };
}).filter(i => i.json.id_contrato);
